#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

Node* newNode(int v) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->val = v; n->left = n->right = NULL; return n;
}

Node* deleteNode(Node* root, int x) {
    if (!root) return NULL;
    if (x < root->val) root->left = deleteNode(root->left, x);
    else if (x > root->val) root->right = deleteNode(root->right, x);
    else {
        if (!root->left && !root->right) { free(root); return NULL; }
        if (!root->left) { Node* r = root->right; free(root); return r; }
        if (!root->right) { Node* l = root->left; free(root); return l; }
        // two children: find inorder successor
        Node* succ = root->right;
        while (succ->left) succ = succ->left;
        root->val = succ->val;
        root->right = deleteNode(root->right, succ->val);
    }
    return root;
}

int exists(Node* root, int x) {
    while (root) {
        if (x == root->val) return 1;
        root = (x < root->val) ? root->left : root->right;
    }
    return 0;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, X; scanf("%d %d", &N, &X);
        Node* nodes[100005] = {0};
        int isChild[100005] = {0};
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir; scanf("%d %d %c", &p, &c, &dir);
            if (!nodes[p]) nodes[p] = newNode(p);
            if (!nodes[c]) nodes[c] = newNode(c);
            if (dir == 'L') nodes[p]->left = nodes[c]; else nodes[p]->right = nodes[c];
            isChild[c] = 1;
        }
        Node* root = NULL;
        if (N == 1) {
            root = newNode(X);
        } else {
            for (int i = 0; i < 100005; ++i) if (nodes[i] && !isChild[i]) { root = nodes[i]; break; }
        }
        if (exists(root, X)) {
            root = deleteNode(root, X);
            printf("Successfully deleted the node!");
        } else {
            printf("Node not found");
        }
        if (T) printf("\n");
    }
    return 0;
}

