#include <bits/stdc++.h>
using namespace std;
struct Node {
    int val;
    Node* left;
    Node* right;
    Node(int v): val(v), left(nullptr), right(nullptr) {}
};

Node* deleteNode(Node* root, int x) {
    if (!root) return nullptr;
    if (x < root->val) root->left = deleteNode(root->left, x);
    else if (x > root->val) root->right = deleteNode(root->right, x);
    else {
        if (!root->left && !root->right) { delete root; return nullptr; }
        if (!root->left) { Node* r = root->right; delete root; return r; }
        if (!root->right) { Node* l = root->left; delete root; return l; }
        // two children: inorder successor
        Node* succ = root->right;
        while (succ->left) succ = succ->left;
        root->val = succ->val;
        root->right = deleteNode(root->right, succ->val);
    }
    return root;
}

bool exists(Node* root, int x) {
    while (root) {
        if (x == root->val) return true;
        root = (x < root->val) ? root->left : root->right;
    }
    return false;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if (!(cin >> T)) return 0;
    while (T--) {
        int N, X; cin >> N >> X;
        unordered_map<int, Node*> mp;
        unordered_set<int> childSet;
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir; cin >> p >> c >> dir;
            if (!mp.count(p)) mp[p] = new Node(p);
            if (!mp.count(c)) mp[c] = new Node(c);
            if (dir == 'L') mp[p]->left = mp[c]; else mp[p]->right = mp[c];
            childSet.insert(c);
        }
        Node* root = nullptr;
        if (N == 1) {
            root = new Node(X);
        } else {
            for (auto &kv : mp) if (!childSet.count(kv.first)) { root = kv.second; break; }
        }
        if (exists(root, X)) {
            root = deleteNode(root, X);
            cout << "Successfully deleted the node!";
        } else {
            cout << "Node not found";
        }
        if (T) cout << '\n';
    }
    return 0;
}
